export const TechIcon: React.FC<TechIconProps> = ({
  name,
  className = "",
  size = 16,
}) => {
  const normalizedName = name.toLowerCase().replace(/[\s\.\-\/]/g, "");

  // Priority 1: DevIcon Metadata (Generated from high-quality SVGs)
  // Check exact match first
  let devicon = deviconMetadata[normalizedName];

  // If no exact match, try partial match (e.g. "jpa / hibernate" -> "hibernate")
  if (!devicon) {
    const entry = Object.entries(deviconMetadata).find(([key]) =>
      normalizedName.includes(key),
    );
    if (entry) devicon = entry[1];
  }

  if (devicon) {
    return (
      <svg
        width={size}
        height={size}
        viewBox={devicon.viewBox}
        className={className}
        xmlns="http://www.w3.org/2000/svg"
        role="img"
        aria-label={name}
        dangerouslySetInnerHTML={{
          __html: `<title>${name}</title>${devicon.content}`,
        }}
      />
    );
  }

  // Priority 2: Manual SVGs for missing or custom icons
  let manualLogo = MANUAL_LOGOS[normalizedName];
  if (!manualLogo) {
    const entry = Object.entries(MANUAL_LOGOS).find(([key]) =>
      normalizedName.includes(key),
    );
    if (entry) manualLogo = entry[1];
  }

  if (manualLogo) {
    return (
      <svg
        width={size}
        height={size}
        viewBox={manualLogo.viewBox || "0 0 24 24"}
        className={className}
        style={manualLogo.color ? { fill: manualLogo.color } : {}}
        xmlns="http://www.w3.org/2000/svg"
        role="img"
        aria-label={name}
      >
        <title>{name}</title>
        {manualLogo.content}
      </svg>
    );
  }

  // Fallbacks to Lucide Icons
  if (normalizedName.includes("flutter"))
    return <Smartphone className={className} size={size} />;
  if (
    normalizedName.includes("webrtc") ||
    normalizedName.includes("video") ||
    normalizedName.includes("audio")
  )
    return <Wifi className={className} size={size} />;
  if (
    normalizedName.includes("socket") ||
    normalizedName.includes("real-time") ||
    normalizedName.includes("sync")
  )
    return <Zap className={className} size={size} />;
  if (
    normalizedName.includes("spring") ||
    normalizedName.includes("api") ||
    normalizedName.includes("node")
  )
    return <Server className={className} size={size} />;
  if (normalizedName.includes("ci/cd") || normalizedName.includes("workflow"))
    return <LucideInfinity className={className} size={size} />;
  if (
    normalizedName.includes("firebase") ||
    normalizedName.includes("cloud") ||
    normalizedName.includes("aws")
  )
    return <Cloud className={className} size={size} />;
  if (
    normalizedName.includes("db") ||
    normalizedName.includes("sql") ||
    normalizedName.includes("database")
  )
    return <Database className={className} size={size} />;
  if (
    normalizedName.includes("architecture") ||
    normalizedName.includes("scalable")
  )
    return <Layers className={className} size={size} />;
  if (
    normalizedName.includes("typescript") ||
    normalizedName.includes("js") ||
    normalizedName.includes("dart")
  )
    return <Code2 className={className} size={size} />;

  return <Cpu className={className} size={size} />;
};
